  styleUrls: ['./badge.css'],
})
export class BadgeComponent {
  @Input() label = '';
  @Input() variant: 'default' | 'primary' | 'success' | 'warning' | 'error' | 'muted' = 'default';
  @Input() size: 'small' | 'medium' | 'large' = 'medium';
