/* =============================================
   Data Table - Wrapper & Layout
   ============================================= */
.fw-data-table-wrapper {
  font-family: 'Nunito Sans', 'Helvetica Neue', Helvetica, Arial, sans-serif;
  font-size: 13px;
  color: #374151;
  background: #ffffff;
  border: 1px solid #E5E7EB;
  border-radius: 8px;
  overflow: hidden;
  position: relative;
}

/* =============================================
   Loading Overlay
   ============================================= */
.fw-data-table__loading-overlay {
  position: absolute;
  inset: 0;
  background: rgba(255, 255, 255, 0.7);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 10;
  border-radius: 8px;
}

.fw-data-table__loading-spinner {
  width: 24px;
  height: 24px;
  border: 3px solid #E5E7EB;
  border-top-color: #0066FF;
  border-radius: 50%;
  animation: fw-spin 0.7s linear infinite;
}

@keyframes fw-spin {
  to { transform: rotate(360deg); }
}

/* =============================================
   Toolbar
   ============================================= */
.fw-data-table__toolbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 14px;
  background: #F9FAFB;
  border-bottom: 1px solid #E5E7EB;
  gap: 8px;
}

.fw-data-table__toolbar-actions {
  display: flex;
  align-items: center;
  gap: 6px;
  flex-wrap: wrap;
}

.fw-data-table__toolbar-btn {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 5px 10px;
  background: #ffffff;
  border: 1px solid #D1D5DB;
  border-radius: 5px;
  font-size: 12px;
  font-weight: 600;
  color: #374151;
  cursor: pointer;
  transition: background-color 0.15s ease, border-color 0.15s ease;
  white-space: nowrap;
}

.fw-data-table__toolbar-btn:hover {
  background: #F3F4F6;
  border-color: #9CA3AF;
}

.fw-data-table__toolbar-btn:focus-visible {
  outline: none;
  box-shadow: 0 0 0 2px rgba(0, 102, 255, 0.4);
}

/* =============================================
   View Toggle
   ============================================= */
.fw-data-table__view-toggle {
  display: flex;
  align-items: center;
  border: 1px solid #D1D5DB;
  border-radius: 5px;
  overflow: hidden;
}

.fw-data-table__view-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 5px 8px;
  background: #ffffff;
  border: none;
  color: #6B7280;
  cursor: pointer;
  transition: background-color 0.15s ease, color 0.15s ease;
}

.fw-data-table__view-btn:hover {
  background: #F3F4F6;
  color: #374151;
}

.fw-data-table__view-btn--active {
  background: #EFF6FF;
  color: #0066FF;
}

.fw-data-table__view-btn:focus-visible {
  outline: none;
  box-shadow: inset 0 0 0 2px rgba(0, 102, 255, 0.4);
}

/* =============================================
   Table
   ============================================= */
.fw-data-table__scroll-container {
  overflow-x: auto;
}

.fw-data-table__table {
  width: 100%;
  border-collapse: collapse;
  table-layout: auto;
}

/* =============================================
   Header Row
   ============================================= */
.fw-data-table__header-row {
  background: #F9FAFB;
  border-bottom: 1px solid #E5E7EB;
}

.fw-data-table__th {
  padding: 10px 12px;
  text-align: left;
  font-size: 12px;
  font-weight: 700;
  color: #6B7280;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  white-space: nowrap;
  user-select: none;
}

.fw-data-table__th--sortable {
  cursor: pointer;
}

.fw-data-table__th--sortable:hover {
  color: #374151;
}

.fw-data-table__th--checkbox,
.fw-data-table__td--checkbox {
  width: 40px;
  padding: 10px 12px;
}

.fw-data-table__th--action,
.fw-data-table__td--action {
  width: 40px;
  text-align: center;
}

.fw-data-table__th-content {
  display: inline-flex;
  align-items: center;
  gap: 4px;
}

/* =============================================
   Sort Icon
   ============================================= */
.fw-data-table__sort-icon {
  color: #D1D5DB;
  display: inline-flex;
  transition: color 0.15s ease;
}

.fw-data-table__th--sortable:hover .fw-data-table__sort-icon {
  color: #9CA3AF;
}

.fw-data-table__sort-icon--asc svg polyline:first-child,
.fw-data-table__sort-icon--desc svg polyline:last-child {
  stroke: #0066FF;
}

.fw-data-table__sort-icon--asc,
.fw-data-table__sort-icon--desc {
  color: #0066FF;
}

/* =============================================
   Body Rows
   ============================================= */
.fw-data-table__row {
  border-bottom: 1px solid #F3F4F6;
  cursor: pointer;
  transition: background-color 0.1s ease;
}

.fw-data-table__row:last-child {
  border-bottom: none;
}

.fw-data-table__row:hover {
  background: #F9FAFB;
}

.fw-data-table__row--selected {
  background: #EFF6FF;
}

.fw-data-table__row--selected:hover {
  background: #DBEAFE;
}

.fw-data-table__td {
  padding: 10px 12px;
  font-size: 13px;
  color: #374151;
  white-space: nowrap;
}

/* =============================================
   Checkbox
   ============================================= */
.fw-data-table__checkbox {
  width: 15px;
  height: 15px;
  cursor: pointer;
  accent-color: #0066FF;
}

/* =============================================
   Row Action Button
   ============================================= */
.fw-data-table__row-action-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 4px;
  background: transparent;
  border: none;
  border-radius: 4px;
  color: #9CA3AF;
  cursor: pointer;
  transition: color 0.15s ease, background-color 0.15s ease;
}

.fw-data-table__row-action-btn:hover {
  color: #374151;
  background: #F3F4F6;
}

.fw-data-table__row-action-btn:focus-visible {
  outline: none;
  box-shadow: 0 0 0 2px rgba(0, 102, 255, 0.4);
}

/* =============================================
   Filter Row
   ============================================= */
.fw-data-table__filter-row {
  background: #F3F4F6;
  border-bottom: 1px solid #E5E7EB;
}

.fw-data-table__th--filter {
  padding: 6px 12px;
}

.fw-data-table__filter-input {
  width: 100%;
  padding: 4px 8px;
  font-size: 12px;
  font-family: inherit;
  color: #374151;
  background: #ffffff;
  border: 1px solid #D1D5DB;
  border-radius: 4px;
  box-sizing: border-box;
  transition: border-color 0.15s ease, box-shadow 0.15s ease;
}

.fw-data-table__filter-input::placeholder {
  color: #9CA3AF;
}

.fw-data-table__filter-input:focus {
  outline: none;
  border-color: #0066FF;
  box-shadow: 0 0 0 2px rgba(0, 102, 255, 0.2);
}

/* =============================================
   Empty State
   ============================================= */
.fw-data-table__empty-cell {
  padding: 32px 12px;
  text-align: center;
  color: #9CA3AF;
  font-size: 13px;
}

/* =============================================
   Pagination Footer
   ============================================= */
.fw-data-table__pagination {
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: 8px;
  padding: 10px 14px;
  border-top: 1px solid #E5E7EB;
  background: #F9FAFB;
}

.fw-data-table__pagination-summary {
  font-size: 12px;
  color: #6B7280;
  white-space: nowrap;
}

.fw-data-table__pagination-controls {
  display: flex;
  align-items: center;
  gap: 2px;
}

.fw-data-table__page-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 28px;
  height: 28px;
  padding: 0 6px;
  background: #ffffff;
  border: 1px solid #D1D5DB;
  border-radius: 4px;
  font-size: 12px;
  font-weight: 600;
  color: #374151;
  cursor: pointer;
  transition: background-color 0.15s ease, border-color 0.15s ease, color 0.15s ease;
}

.fw-data-table__page-btn:hover:not(:disabled) {
  background: #F3F4F6;
  border-color: #9CA3AF;
}

.fw-data-table__page-btn--active {
  background: #0066FF;
  border-color: #0066FF;
  color: #ffffff;
}

.fw-data-table__page-btn--active:hover {
  background: #0052CC;
  border-color: #0052CC;
}

.fw-data-table__page-btn:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

.fw-data-table__page-btn:focus-visible {
  outline: none;
  box-shadow: 0 0 0 2px rgba(0, 102, 255, 0.4);
}

.fw-data-table__page-size {
  display: flex;
  align-items: center;
  gap: 6px;
}

.fw-data-table__page-size-label {
  font-size: 12px;
  color: #6B7280;
}

.fw-data-table__page-size-select {
  padding: 3px 6px;
  font-size: 12px;
  font-family: inherit;
  color: #374151;
  background: #ffffff;
  border: 1px solid #D1D5DB;
  border-radius: 4px;
  cursor: pointer;
}

.fw-data-table__page-size-select:focus {
  outline: none;
  border-color: #0066FF;
  box-shadow: 0 0 0 2px rgba(0, 102, 255, 0.2);
}

