  border-color: #d9d9e2;
  color: #222222;
}

.flywheel-input--contained.flywheel-input--light .flywheel-input__field::placeholder {
  color: #8f8fa3;
}

.flywheel-input--outline.flywheel-input--dark .flywheel-input__field {
  background: transparent;
  border-color: rgba(255, 255, 255, 0.32);
  color: #f5f5f5;
}

.flywheel-input--outline.flywheel-input--dark .flywheel-input__field::placeholder {
  color: #7a7a7a;
}

.flywheel-input--outline.flywheel-input--light .flywheel-input__field {
  background: transparent;
  border-color: #d9d9e2;
  color: #222222;
}

.flywheel-input--outline.flywheel-input--light .flywheel-input__field::placeholder {
  color: #8f8fa3;
}

.flywheel-input--focused .flywheel-input__field {
  border-color: #00b4ff;
  box-shadow: 0 0 0 3px rgba(0, 180, 255, 0.5), 0 0 16px rgba(0, 180, 255, 0.35);
}

.flywheel-input--focused.flywheel-input--dark .flywheel-input__field {
  background: #1a1a1a;
}

.flywheel-input--pressed .flywheel-input__field {
  border-color: #00b4ff;
  box-shadow: 0 0 0 2px rgba(0, 180, 255, 0.4);
  transform: translateY(1px);
}

.flywheel-input--disabled {
  opacity: 0.48;
}

.flywheel-input--disabled .flywheel-input__field {
  cursor: not-allowed;
}

.flywheel-input--dark {
  color: #f5f5f5;
}

.flywheel-input--light {
  color: #2d2d35;
}

/* Ensure real focus receives same visible outline as the focused state class */
.flywheel-input__field:focus,
.flywheel-input__field:focus-visible {
  border-color: #00b4ff;
  box-shadow: 0 0 0 3px rgba(0, 180, 255, 0.5), 0 0 16px rgba(0, 180, 255, 0.35);
  outline: none;
}

/* Stronger specificity to ensure dark contained inputs render with black background */
.flywheel-input.flywheel-input--contained.flywheel-input--dark .flywheel-input__field {
  background: #1a1a1a !important;
  color: #f5f5f5 !important;
}

