.radio-group {
  border: none;
  padding: 0;
  margin: 0;
  font-family: 'Nunito Sans', 'Helvetica Neue', Helvetica, Arial, sans-serif;

}

.radio-group__label {
  font-size: 0.9375rem;
  font-weight: 500;
  color: #E5E7EB;
  margin-bottom: 0.75rem;
  display: block;
}

.radio-group__options {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.radio-group--horizontal {
  flex-direction: row;
  flex-wrap: wrap;
  gap: 1.5rem;
}

.radio-group--disabled {
  opacity: 0.5;
  pointer-events: none;
}

.radio-option {
  display: flex;
  align-items: center;
  gap: 0.625rem;
  cursor: pointer;
  padding: 0.25rem 0;
}

.radio-option__input {
  position: absolute;
  opacity: 0;
  width: 0;
  height: 0;
}

.radio-option__circle {
  width: 18px;
  height: 18px;
  border-radius: 50%;
  border: 2px solid #6B7280;
